#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    if (N <= 0) {
        printf("N must be a positive integer.\n");
        return 1;
    }

    int current_num;
    double sum = 0.0;
    int min_val;
    int max_val;

    // Read the first number to initialize min_val and max_val
    scanf("%d", &current_num);
    sum += current_num;
    min_val = current_num;
    max_val = current_num;

    // Process the remaining N-1 numbers
    for (int i = 1; i < N; i++) {
        scanf("%d", &current_num);
        sum += current_num;
        if (current_num < min_val) {
            min_val = current_num;
        }
        if (current_num > max_val) {
            max_val = current_num;
        }
    }

    double average = sum / N;

    printf("Average: %.2f\n", average);
    printf("Min: %d\n", min_val);
    printf("Max: %d\n", max_val);

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int operand1, operand2;
        char operator_char;

        // Read operand1, then operator, then operand2
        // Using a space before %c to consume any leftover newline characters
        scanf("%d %c %d", &operand1, &operator_char, &operand2);

        int result;
        int error = 0;

        switch (operator_char) {
            case '+':
                result = operand1 + operand2;
                break;
            case '-':
                result = operand1 - operand2;
                break;
            case '*':
                result = operand1 * operand2;
                break;
            case '/':
                if (operand2 == 0) {
                    printf("Error: Division by zero.\n");
                    error = 1;
                } else {
                    result = operand1 / operand2;
                }
                break;
            default:
                printf("Error: Invalid operator.\n");
                error = 1;
                break;
        }

        if (!error) {
            printf("Result: %d\n", result);
        }
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    int positive_count = 0;
    int negative_count = 0;
    int zero_count = 0;

    for (int i = 0; i < N; i++) {
        int num;
        scanf("%d", &num);

        if (num > 0) {
            positive_count++;
        } else if (num < 0) {
            negative_count++;
        } else { // num == 0
            zero_count++;
        }
    }

    printf("Positive: %d\n", positive_count);
    printf("Negative: %d\n", negative_count);
    printf("Zero: %d\n", zero_count);

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int M;
        scanf("%d", &M);

        int original_M = M; // Keep original for printing if needed, though not required here
        int digit_sum = 0;

        if (M == 0) { // Special case for 0
            digit_sum = 0;
        } else {
            while (M > 0) {
                int digit = M % 10; // Get the last digit
                digit_sum += digit;  // Add to sum
                M /= 10;             // Remove the last digit
            }
        }
        printf("Sum of digits: %d\n", digit_sum);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int year;
        scanf("%d", &year);

        int is_leap = 0; // Flag to indicate if it's a leap year

        if (year % 400 == 0) {
            is_leap = 1;
        } else if (year % 100 == 0) {
            is_leap = 0; // Divisible by 100 but not 400, so not a leap year
        } else if (year % 4 == 0) {
            is_leap = 1;
        } else {
            is_leap = 0;
        }

        if (is_leap) {
            printf("Leap Year\n");
        } else {
            printf("Not a Leap Year\n");
        }
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        double principal, rate, time;
        scanf("%lf %lf %lf", &principal, &rate, &time);

        double interest = (principal * rate * time) / 100.0;

        printf("Simple Interest: %.2f\n", interest);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int score;
        scanf("%d", &score);

        char grade;

        if (score >= 90 && score <= 100) {
            grade = 'A';
        } else if (score >= 80 && score < 90) {
            grade = 'B';
        } else if (score >= 70 && score < 80) {
            grade = 'C';
        } else if (score >= 60 && score < 70) {
            grade = 'D';
        } else if (score >= 0 && score < 60) {
            grade = 'F';
        } else {
            // Handle scores outside 0-100 range, though problem constraints say 0-100
            grade = '?';
        }
        printf("Grade: %c\n", grade);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int base, exponent;
        scanf("%d %d", &base, &exponent);

        long long result = 1; // Use long long for result in case of larger powers

        if (exponent == 0) {
            result = 1;
        } else if (base == 0) {
            result = 0; // 0^positive_exponent is 0
        } else {
            for (int j = 0; j < exponent; j++) {
                result *= base;
            }
        }
        printf("Result: %lld\n", result);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int num;
        scanf("%d", &num);

        long long factorial = 1; // Use long long for factorial as it grows quickly

        if (num < 0) {
            // Should not happen based on constraints, but good practice
            printf("Factorial of negative numbers is undefined.\n");
        } else if (num == 0) {
            factorial = 1; // 0! is 1
        } else {
            for (int j = 1; j <= num; j++) {
                factorial *= j;
            }
        }
        printf("Factorial: %lld\n", factorial);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    for (int i = 0; i < N; i++) {
        int x, y;
        scanf("%d %d", &x, &y);

        if (x == 0 || y == 0) {
            printf("On an axis\n");
        } else if (x > 0 && y > 0) {
            printf("Quadrant 1\n");
        } else if (x < 0 && y > 0) {
            printf("Quadrant 2\n");
        } else if (x < 0 && y < 0) {
            printf("Quadrant 3\n");
        } else { // x > 0 && y < 0
            printf("Quadrant 4\n");
        }
    }

    return 0;
}
